from instructor import from_openai
from pydantic import BaseModel, Field, validator
from typing import Literal
from vex import verify

class RiskAssessment(BaseModel):
    risk_score: int = Field(ge=0, le=1000)
    factors: list[Literal['AGE', 'DRIVING_RECORD', 'COVERAGE_AMOUNT']]  # No protected classes

    @validator('factors')
    def no_protected(cls, v):
        protected = {'ZIP_CODE', 'GENDER', 'ETHNICITY'}
        if any(f in protected for f in v): raise ValueError('Protected class detected')
        return v

openai_client = from_openai(OpenAI())

@verify
async def assess_risk(applicant_data: str) -> RiskAssessment:
    response = await openai_client.chat.completions.create(
        model="gpt-4o",
        response_model=RiskAssessment,
        messages=[{"role": "user", "content": applicant_data}]
    )
    return response

import { fromOpenai } from '@instructor-ai/instructor'; // npm i instructor

import { z } from 'zod';
import { verify } from '@vex-sdk/core';

const FCRA_DISCLOSURE = z.object({
  credit_factors_used: z.array(z.enum(['PAYMENT_HISTORY', 'DEBT_UTILIZATION', 'LENGTH_OF_CREDIT'])),
  explanation: z.string().min(100).describe('FCRA-mandated explanation'),
  inquiry_date: z.string().datetime(),
  no_discrimination: z.literal(true).describe('Anti-discrimination compliance flag')
});

type FCRADisclosure = z.infer<typeof FCRA_DISCLOSURE>;

const instructor = fromOpenai(OpenAI({ apiKey: process.env.OPENAI_API_KEY }));

export const extractFCRA = verify(
  async (prompt: string): Promise<FCRADisclosure> => {
    const completion = await instructor.chat.completions.create({
      model: 'gpt-4o',
      response_model: FCRA_DISCLOSURE,
      messages: [{ role: 'user', content: `Extract FCRA disclosure from: ${prompt}` }],
    });
    return completion;
  },
  { schema: FCRA_DISCLOSURE }
);
